    var liveBank = (grade11DepthBank && grade11DepthBank.length) ? grade11DepthBank : ((grade11BalanceBank && grade11BalanceBank.length) ? grade11BalanceBank : ((probBank && probBank.length) ? probBank : ((socialBank && socialBank.length) ? socialBank : ((obzhBank && obzhBank.length) ? obzhBank : litBank))));
    var hasLiveBank = !!(liveBank && liveBank.length);
    var liveGen = grade11DepthBank && grade11DepthBank.length ? makeWave87jGrade11Gen(topic, subject, grade11DepthBank) : (grade11BalanceBank && grade11BalanceBank.length ? makeWave87gGrade11Gen(topic, subject, grade11BalanceBank) : (probBank && probBank.length ? makeWave87hProbGen(topic, subject, probBank) : (socialBank && socialBank.length ? makeWave87fSocialGen(topic, subject, socialBank) : (obzhBank && obzhBank.length ? makeWave87bObzhGen(topic, subject, obzhBank) : (litBank && litBank.length ? makeWave87aLitGen(topic, subject, litBank) : null)))));
